B.PT=new A.T(B.ac,"Tense signals when an action happens","In aviation English, choosing the right tense is critical. ATC uses **present simple** for permanent facts, **present continuous** for current actions, and **past simple** for completed events in reports.\n\nMixing tenses in checklists or reports is a common exam error.",null,null,null)
B.Ly=new A.op(4,"tensesTimeline")
B.PU=new A.T(B.eU,"Tenses on a timeline",null,null,B.Ly,null)
B.OX=new A.T(B.B,"Simple vs. Continuous",'**Present Simple** \u2014 facts, routines, permanent states\n\u2192 "The ILS localizer **operates** on frequencies 108\u2013111.95 MHz."\n\n**Present Continuous** \u2014 actions happening now, temporary\n\u2192 "The aircraft **is climbing** through flight level 180."\n\n**Past Simple** \u2014 completed events (reports, logs)\n\u2192 "The crew **performed** the before-start checklist at 0612Z."\n\n**Past Continuous** \u2014 ongoing past action interrupted\n\u2192 "The aircraft **was taxiing** when the bird strike **occurred**."',null,null,null)
B.Kl=new A.aE("The aircraft is currently holding at ELVIN fix due to traffic congestion.","U\xe7ak, trafik yo\u011funlu\u011fu nedeniyle \u015fu anda ELVIN noktas\u0131nda bekleme yap\u0131yor.","is currently holding")
