B.a1I=new A.ab(-21,B.ai,252,"What is the function of the rudder?",B.RC,2,B.L,null,null,null)
B.TU=s(["The fuselage section","The engine housing","The cockpit area","The cargo hold"],t.s)
B.a1i=new A.ab(-22,B.ai,253,'The "nacelle" refers to which part of the aircraft?',B.TU,1,B.A,null,null,null)
