B.Wh=s(["Aircraft is on its way to the gate","Aircraft is grounded due to an unserviceable condition","Aircraft is authorized to operate with deferred defects","Aircraft has been overhauled"],t.s)
B.a1j=new A.ab(-262,B.ai,332,'An "AOG" status means:',B.Wh,1,B.A,null,null,null)
B.WP=s(["Aircraft landing on wrong runway","Any unauthorized presence on the runway","Runway excursion due to brake failure","ATC error causing runway conflict"],t.s)
